&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;&lt;strong&gt;Location:&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;
&lt;ul&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;This role is hybrid (4 days a week in our Nashville office)&lt;/li&gt;
&lt;/ul&gt;
